sql:
SELECT severity, COUNT(*) AS condition_count
FROM medical_conditions
GROUP BY severity;

SELECT strain_name, average_thc
FROM strains
ORDER BY average_thc DESC;

SELECT user_id, rating, comments
FROM user_strain_experiences
WHERE strain_id = 0;

external_knowledge:
- A 'popular strain' refers to a strain with more than 5 user reviews; 
- 'start of the year' is January 1; 
- 'end of the third quarter' is September 30.
